        $$Propone planes de intervención para la atención de estudiantes con problemas de aprendizaje en función de las características cognitivas, físicas, motora y socio emocionales del niño$$,
        $$Tiene la capacidad de propone planes de intervención para la atención de estudiantes con problemas de aprendizaje en función de las características cognitivas, físicas, motora y socio emocionales del niño$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1288$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Técnicas básicas de atención a la Salud.$$, $$CEDS1289$$,
        3, 8,
        FALSE, $$specialty$$,
        $$El curso Técnicas básicas de atención a la Salud, tiene como resultado de aprendizaje, el desarrollo de la capacidad “Implementa planes de atención a la salud sobre la base de los protocolos de bio seguridad, conocimientos básicos de primeros auxilios, líneas de atención, técnicas de intervención y prevención de la salud “Conduce procesos de enseñanza aprendizaje sobre la base de los principios de enfoques didácticos, procesos metodológicos, recursos educativos y del dominio disciplinar de las áreas curriculares”, según Perfil de Egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa, en un entorno real de enseñanza aprendizaje, situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades como exposiciones, debates, foros, estudio de casos, trabajo cooperativo y análisis de lecturas, que posibiliten el conocimiento del aprendizaje de diseño Curricular Básico Nacional para la carrera profesional de profesor de Educación Primaria, tomando en base el Área de Ciencia, Tecnología y Ambiente, analiza el Plan Curricular de Educación Primaria del Ministerio de Educación, relacionado al Proceso de Enseñanza Aprendizaje, la matriz curricular, el Área de Ciencia, tecnología y Ambiente, de Educación Primaria, propósito del Área de Ciencia, tecnología y Ambiente, técnicas básicas en Atención a la Salud y primeros Auxilios, como Técnica Básica de atención, en el aula y escuela. Además, desarrolla habilidades vinculadas a analizar y evaluar el Plan Curricular de Educación Primaria del Ministerio de Educación, relacionándolo al Proceso de Enseñanza – Aprendizaje del curso en mención, asume a través del Proceso de Enseñanza – Aprendizaje las competencias y las líneas (básica, fundamental, profesional) de la matriz curricular, maneja el Área de Ciencia, Tecnología y Ambiente, de Educación Primaria y asume el Propósito de dicha Área, indaga, respecto a las Técnicas básicas en Atención a la Salud, y asume los Primeros Auxilios, como Técnica Básica de atención, que permiten atender las emergencias en el aula, maneja nociones básicas de primeros auxilios para principiantes e instalan un Botiquín de Primeros Auxilios, en su aula, a fin de atender las emergencias.”$$,
        $$Conduce procesos de enseñanza aprendizaje sobre la base de los principios de enfoques didácticos, procesos metodológicos, recursos educativos y del dominio disciplinar de las áreas curriculares$$,
        $$Implementa planes de atención a la salud sobre la base de los protocolos de bio seguridad, conocimientos básicos de primeros auxilios, líneas de atención, técnicas de intervención y prevención de la salud$$,
        $$Tiene la capacidad de implementa planes de atención a la salud sobre la base de los protocolos de bio seguridad, conocimientos básicos de primeros auxilios, líneas de atención, técnicas de intervención y prevención de la salud$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1289$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Gamificación$$, $$CEDS1286$$,
        3, 8,
        FALSE, $$specialty$$,
        $$El curso de Gamificación tiene como resultado de aprendizaje el desarrollo de la capacidad “Emplea la estrategia de la gamificación en situaciones de aprendizaje sobre la base de sus fundamentos, características, procesos metodológicos y el enfoque del aprendizaje lúdico”, según Perfil de Egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades como exposiciones, debates, foros, estudio de casos, trabajo cooperativo y análisis de lecturas, que posibiliten el conocimiento de gamificación, sus definiciones e importancia, sus presupuestos psicopedagógicos y su aplicación -Importancia y su aplicación en el proceso formativo, los modelos de comportamiento en relación a la gamificación, dinámicas de motivación, el error como elemento de partida para el aprendizaje, el juego., sus definiciones, utilidad, clasificación, así como las mediciones y métodos de evaluación que reflejen un mundo cambiante de conocimientos, habilidades y valores, técnicas de trabajo en pequeños grupos, Phillip 66,dramatizaciones,juego de roles. Además, desarrolla habilidades vinculadas a planifica dinámicas para promover la expresión de los estudiantes, identifica la gamificación como estrategia didáctica para promover aprendizajes, uso de casos y otros medios para estimular la situación real del trabajo, adaptación de los métodos y materiales a un medio de cambio constante, promueve un currículo que estimule a los estudiantes a aprender por sí mismos, uso de tecnologías creativas y valora la aportación de cada elemento a la experiencia lúdica.$$,
        $$Emplea la estrategia de la gamificación en situaciones de aprendizaje sobre la base de sus fundamentos, características, procesos metodológicos y el enfoque del aprendizaje lúdico$$,
        $$Emplea la estrategia de la gamificación en situaciones de aprendizaje sobre la base de sus fundamentos, características, procesos metodológicos y el enfoque del aprendizaje lúdico$$,
        $$Tiene la capacidad de emplea la estrategia de la gamificación en situaciones de aprendizaje sobre la base de sus fundamentos, características, procesos metodológicos y el enfoque del aprendizaje lúdico$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1286$$);

END $body$;

-- VERIFICACIÓN
SELECT p.name,
  COUNT(c.id)                                              AS total,
  SUM(CASE WHEN c.is_common         THEN 1 ELSE 0 END)    AS comunes,
  SUM(CASE WHEN c.scope='specific'  THEN 1 ELSE 0 END)    AS especificos,
  SUM(CASE WHEN c.scope='specialty' THEN 1 ELSE 0 END)    AS especialidad,
  SUM(CASE WHEN c.capacidad IS NOT NULL THEN 1 ELSE 0 END) AS con_capacidad
FROM programs p
LEFT JOIN courses c ON c.program_id = p.id
GROUP BY p.name ORDER BY p.name;